import{_ as a,o as r,c as t,ag as n}from"./chunks/framework.5wcOFaQl.js";const m=JSON.parse('{"title":"Glossar 📖","description":"","frontmatter":{},"headers":[],"relativePath":"glossar.md","filePath":"glossar.md"}'),i={name:"glossar.md"};function o(l,e,h,s,d,u){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="glossar-📖" tabindex="-1">Glossar 📖 <a class="header-anchor" href="#glossar-📖" aria-label="Permalink to &quot;Glossar 📖&quot;">​</a></h1><p>Wichtige Begriffe rund um Hermes Agent – kurz erklärt.</p><hr><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><h3 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h3><p>Ein KI-gesteuerter Assistent, der Tools nutzt, um Aufgaben autonom auszuführen. Hermes ist ein solcher Agent.</p><h3 id="acp-agent-communication-protocol" tabindex="-1">ACP (Agent Communication Protocol) <a class="header-anchor" href="#acp-agent-communication-protocol" aria-label="Permalink to &quot;ACP (Agent Communication Protocol)&quot;">​</a></h3><p>Ein Protokoll, das es verschiedenen KI-Agenten ermöglicht, miteinander zu kommunizieren. Ermöglicht z.B. Claude Code von Hermes aus zu steuern.</p><h3 id="anthropic" tabindex="-1">Anthropic <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;Anthropic&quot;">​</a></h3><p>Anbieter der Claude-Modellfamilie. Unterstützter Provider in Hermes.</p><hr><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><h3 id="base-url" tabindex="-1">Base URL <a class="header-anchor" href="#base-url" aria-label="Permalink to &quot;Base URL&quot;">​</a></h3><p>Die Basis-URL eines API-Endpoints. Für Custom-Provider oder lokale Modelle (z.B. Ollama: <code>http://localhost:11434/v1</code>).</p><h3 id="branch-protection" tabindex="-1">Branch Protection <a class="header-anchor" href="#branch-protection" aria-label="Permalink to &quot;Branch Protection&quot;">​</a></h3><p>GitHub-Einstellung, die direkte Pushes auf geschützte Branches (z.B. <code>main</code>) verhindert. In Hermes-Workflows oft relevant.</p><hr><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><h3 id="cli-command-line-interface" tabindex="-1">CLI (Command Line Interface) <a class="header-anchor" href="#cli-command-line-interface" aria-label="Permalink to &quot;CLI (Command Line Interface)&quot;">​</a></h3><p>Die Kommandozeilen-Oberfläche. Hermes wird primär über die CLI gesteuert.</p><h3 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;Config&quot;">​</a></h3><p>Die Konfigurationsdatei <code>~/.hermes/config.yaml</code>. Steuert alle Einstellungen von Hermes.</p><h3 id="credential-pool" tabindex="-1">Credential Pool <a class="header-anchor" href="#credential-pool" aria-label="Permalink to &quot;Credential Pool&quot;">​</a></h3><p>Mehrere API-Keys für denselben Provider. Hermes rotiert automatisch bei Erschöpfung.</p><h3 id="cron" tabindex="-1">Cron <a class="header-anchor" href="#cron" aria-label="Permalink to &quot;Cron&quot;">​</a></h3><p>Zeitgesteuerte Aufgaben. Hermes kann Cron-Jobs ausführen – z.B. tägliche Reports.</p><h3 id="custom-domain" tabindex="-1">Custom Domain <a class="header-anchor" href="#custom-domain" aria-label="Permalink to &quot;Custom Domain&quot;">​</a></h3><p>Eigene Domain für GitHub Pages (z.B. <code>meineseite.de</code> statt <code>user.github.io/repo</code>).</p><hr><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><h3 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h3><p>Fehlersuche. Hermes hat Skills für systematisches Debuggen von Code.</p><h3 id="deepseek" tabindex="-1">DeepSeek <a class="header-anchor" href="#deepseek" aria-label="Permalink to &quot;DeepSeek&quot;">​</a></h3><p>Chinesisches KI-Unternehmen. Bietet kostengünstige LLM-Modelle, aktuell genutzt in diesem Compendium.</p><h3 id="delegate-task" tabindex="-1">Delegate Task <a class="header-anchor" href="#delegate-task" aria-label="Permalink to &quot;Delegate Task&quot;">​</a></h3><p>Aufgabe an einen Sub-Agenten delegieren. Ermöglicht parallele Bearbeitung.</p><h3 id="discord" tabindex="-1">Discord <a class="header-anchor" href="#discord" aria-label="Permalink to &quot;Discord&quot;">​</a></h3><p>Messaging-Plattform. Hermes kann per Discord-Gateway betrieben werden.</p><hr><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><h3 id="enforce-https" tabindex="-1">Enforce HTTPS <a class="header-anchor" href="#enforce-https" aria-label="Permalink to &quot;Enforce HTTPS&quot;">​</a></h3><p>Erzwingt verschlüsselte Verbindung für GitHub Pages. Wichtig bei Custom Domains.</p><h3 id="env-environment" tabindex="-1">Env (Environment) <a class="header-anchor" href="#env-environment" aria-label="Permalink to &quot;Env (Environment)&quot;">​</a></h3><p>Umgebungsvariablen. In <code>~/.hermes/.env</code> werden API-Keys gespeichert.</p><hr><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><h3 id="fork" tabindex="-1">Fork <a class="header-anchor" href="#fork" aria-label="Permalink to &quot;Fork&quot;">​</a></h3><p>Abspaltung eines GitHub-Repos. Ermöglicht eigene Änderungen am Original-Projekt.</p><h3 id="frontmatter" tabindex="-1">Frontmatter <a class="header-anchor" href="#frontmatter" aria-label="Permalink to &quot;Frontmatter&quot;">​</a></h3><p>YAML-Bereich am Anfang einer Markdown-Datei. Wird für Skill-Metadaten verwendet.</p><hr><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><h3 id="gateway" tabindex="-1">Gateway <a class="header-anchor" href="#gateway" aria-label="Permalink to &quot;Gateway&quot;">​</a></h3><p>Der Dienst, der Hermes mit Messaging-Plattformen verbindet (Telegram, Discord, etc.).</p><h3 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to &quot;GitHub Actions&quot;">​</a></h3><p>CI/CD-Plattform von GitHub. Wird für Auto-Deploy von VitePress-Seiten genutzt.</p><h3 id="github-pages" tabindex="-1">GitHub Pages <a class="header-anchor" href="#github-pages" aria-label="Permalink to &quot;GitHub Pages&quot;">​</a></h3><p>Hosting-Dienst von GitHub. Statische Webseiten direkt aus dem Repository.</p><h3 id="glsl" tabindex="-1">GLSL <a class="header-anchor" href="#glsl" aria-label="Permalink to &quot;GLSL&quot;">​</a></h3><p>OpenGL Shading Language. Wird in Vulkan-Compute-Shadern für GPU-Simulationen verwendet.</p><hr><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><h3 id="hermes-agent" tabindex="-1">Hermes Agent <a class="header-anchor" href="#hermes-agent" aria-label="Permalink to &quot;Hermes Agent&quot;">​</a></h3><p>Open-Source KI-Agent von Nous Research. Läuft im Terminal, auf Messaging-Plattformen und in der IDE.</p><h3 id="hf-hugging-face" tabindex="-1">HF (Hugging Face) <a class="header-anchor" href="#hf-hugging-face" aria-label="Permalink to &quot;HF (Hugging Face)&quot;">​</a></h3><p>Plattform für ML-Modelle. Hermes unterstützt HF-Token für Modellzugriff.</p><h3 id="home-channel" tabindex="-1">Home Channel <a class="header-anchor" href="#home-channel" aria-label="Permalink to &quot;Home Channel&quot;">​</a></h3><p>Der Standard-Chat-Kanal im Gateway. <code>/sethome</code> markiert den aktuellen Kanal.</p><hr><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><h3 id="ide-integrated-development-environment" tabindex="-1">IDE (Integrated Development Environment) <a class="header-anchor" href="#ide-integrated-development-environment" aria-label="Permalink to &quot;IDE (Integrated Development Environment)&quot;">​</a></h3><p>Programmier-Umgebung. Hermes kann in VS Code, Cursor &amp; Co. integriert werden.</p><h3 id="impressum" tabindex="-1">Impressum <a class="header-anchor" href="#impressum" aria-label="Permalink to &quot;Impressum&quot;">​</a></h3><p>Pflichtangabe nach §5 DDG für Webseiten in Deutschland. Im Compendium im Footer verlinkt.</p><hr><h2 id="j" tabindex="-1">J <a class="header-anchor" href="#j" aria-label="Permalink to &quot;J&quot;">​</a></h2><h3 id="jas2-jurgen-s-advanced-simulation-2" tabindex="-1">JAS2 (Jürgen&#39;s Advanced Simulation 2) <a class="header-anchor" href="#jas2-jurgen-s-advanced-simulation-2" aria-label="Permalink to &quot;JAS2 (Jürgen&#39;s Advanced Simulation 2)&quot;">​</a></h3><p>N-Body-Simulationsprojekt des Autors. Parallel zum Compendium entwickelt.</p><hr><h2 id="k" tabindex="-1">K <a class="header-anchor" href="#k" aria-label="Permalink to &quot;K&quot;">​</a></h2><h3 id="key-api-key" tabindex="-1">Key (API-Key) <a class="header-anchor" href="#key-api-key" aria-label="Permalink to &quot;Key (API-Key)&quot;">​</a></h3><p>Geheimer Schlüssel zur Authentifizierung bei einem LLM-Provider. Wird in der <code>.env</code> gespeichert.</p><hr><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><h3 id="llm-large-language-model" tabindex="-1">LLM (Large Language Model) <a class="header-anchor" href="#llm-large-language-model" aria-label="Permalink to &quot;LLM (Large Language Model)&quot;">​</a></h3><p>Großes Sprachmodell. Die KI hinter Hermes (z.B. Claude, DeepSeek, GPT-4).</p><h3 id="lm-studio" tabindex="-1">LM Studio <a class="header-anchor" href="#lm-studio" aria-label="Permalink to &quot;LM Studio&quot;">​</a></h3><p>Tool zum lokalen Ausführen von LLMs. Hermes kann darauf via Custom Endpoint zugreifen.</p><h3 id="local-model" tabindex="-1">Local Model <a class="header-anchor" href="#local-model" aria-label="Permalink to &quot;Local Model&quot;">​</a></h3><p>Ein LLM, das auf dem eigenen Rechner läuft (z.B. über Ollama, LM Studio).</p><hr><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><h3 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h3><p>Standard für externe Tools und Datenquellen. Hermes unterstützt MCP-Server.</p><h3 id="memory" tabindex="-1">Memory <a class="header-anchor" href="#memory" aria-label="Permalink to &quot;Memory&quot;">​</a></h3><p>Das persistente Gedächtnis von Hermes. Merkt sich Fakten über den Benutzer über Sessions hinweg.</p><h3 id="mpi-message-passing-interface" tabindex="-1">MPI (Message Passing Interface) <a class="header-anchor" href="#mpi-message-passing-interface" aria-label="Permalink to &quot;MPI (Message Passing Interface)&quot;">​</a></h3><p>Standard für parallele Berechnungen in Supercomputern. Wird in JAS2-Simulationen genutzt.</p><h3 id="multi-agent" tabindex="-1">Multi-Agent <a class="header-anchor" href="#multi-agent" aria-label="Permalink to &quot;Multi-Agent&quot;">​</a></h3><p>Mehrere Hermes-Instanzen, die parallel arbeiten. Realisierbar via tmux oder delegation.</p><hr><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><h3 id="npx" tabindex="-1">npx <a class="header-anchor" href="#npx" aria-label="Permalink to &quot;npx&quot;">​</a></h3><p>Node Package Runner. Führt Node-Pakete aus, ohne sie global zu installieren.</p><h3 id="nous-research" tabindex="-1">Nous Research <a class="header-anchor" href="#nous-research" aria-label="Permalink to &quot;Nous Research&quot;">​</a></h3><p>Das Unternehmen hinter Hermes Agent. Entwickelt auch eigene KI-Modelle.</p><hr><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><h3 id="oauth" tabindex="-1">OAuth <a class="header-anchor" href="#oauth" aria-label="Permalink to &quot;OAuth&quot;">​</a></h3><p>Offener Standard für Authentifizierung. Wird von einigen Providern (z.B. Nous Portal) genutzt.</p><h3 id="ollama" tabindex="-1">Ollama <a class="header-anchor" href="#ollama" aria-label="Permalink to &quot;Ollama&quot;">​</a></h3><p>Tool zum lokalen Ausführen von LLMs. Hermes kann über Custom Endpoint darauf zugreifen.</p><h3 id="openrouter" tabindex="-1">OpenRouter <a class="header-anchor" href="#openrouter" aria-label="Permalink to &quot;OpenRouter&quot;">​</a></h3><p>Vermittler für viele LLM-Provider. Ein API-Key reicht für Zugriff auf 100+ Modelle.</p><h3 id="opensim" tabindex="-1">OpenSim <a class="header-anchor" href="#opensim" aria-label="Permalink to &quot;OpenSim&quot;">​</a></h3><p>Open-Source-Plattform für virtuelle Welten. Ein Projekt des Autors neben Hermes.</p><hr><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><h3 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h3><p>Separate Hermes-Konfigurationen. Eigene Configs, Skills, Sessions für verschiedene Projekte.</p><h3 id="provider" tabindex="-1">Provider <a class="header-anchor" href="#provider" aria-label="Permalink to &quot;Provider&quot;">​</a></h3><p>LLM-Anbieter (OpenRouter, Anthropic, DeepSeek, etc.). In Hermes wechselbar ohne Config-Änderung.</p><h3 id="pty-pseudo-terminal" tabindex="-1">PTY (Pseudo-Terminal) <a class="header-anchor" href="#pty-pseudo-terminal" aria-label="Permalink to &quot;PTY (Pseudo-Terminal)&quot;">​</a></h3><p>Emuliert ein Terminal für interaktive Programme. Nötig für Tools wie Claude Code im Hermes-Subprozess.</p><hr><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><h3 id="reasoning" tabindex="-1">Reasoning <a class="header-anchor" href="#reasoning" aria-label="Permalink to &quot;Reasoning&quot;">​</a></h3><p>Die Fähigkeit eines LLMs, Schritt-für-Schritt zu denken. Steuerbar mit <code>/reasoning</code>.</p><h3 id="red-teaming" tabindex="-1">Red Teaming <a class="header-anchor" href="#red-teaming" aria-label="Permalink to &quot;Red Teaming&quot;">​</a></h3><p>Sicherheitstests für KI-Modelle. Versucht, Schutzmechanismen zu umgehen.</p><hr><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><h3 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to &quot;Session&quot;">​</a></h3><p>Ein Gesprächsdurchlauf in Hermes. Enthält den gesamten Nachrichtenverlauf.</p><h3 id="sha-commit-sha" tabindex="-1">SHA (Commit SHA) <a class="header-anchor" href="#sha-commit-sha" aria-label="Permalink to &quot;SHA (Commit SHA)&quot;">​</a></h3><p>Eindeutige ID eines Git-Commits. Einige Repos verlangen Actions, die auf SHAs statt Tags gepinnt sind.</p><h3 id="skill" tabindex="-1">Skill <a class="header-anchor" href="#skill" aria-label="Permalink to &quot;Skill&quot;">​</a></h3><p>Wiederverwendbare Anleitung für Hermes. Kann bei Bedarf geladen und ausgeführt werden.</p><h3 id="sub-agent" tabindex="-1">Sub-Agent <a class="header-anchor" href="#sub-agent" aria-label="Permalink to &quot;Sub-Agent&quot;">​</a></h3><p>Ein von Hermes gestarteter Nebenprozess für parallele Aufgaben. Läuft isoliert.</p><h3 id="system-prompt" tabindex="-1">System Prompt <a class="header-anchor" href="#system-prompt" aria-label="Permalink to &quot;System Prompt&quot;">​</a></h3><p>Die Grundinstruktionen für das LLM. Definiert Persönlichkeit, Tools und Verhalten.</p><hr><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><h3 id="telegram" tabindex="-1">Telegram <a class="header-anchor" href="#telegram" aria-label="Permalink to &quot;Telegram&quot;">​</a></h3><p>Messaging-Plattform mit exzellenter Bot-API. Empfohlen für Hermes-Gateway.</p><h3 id="terminal-tool" tabindex="-1">Terminal Tool <a class="header-anchor" href="#terminal-tool" aria-label="Permalink to &quot;Terminal Tool&quot;">​</a></h3><p>Hermes&#39; Fähigkeit, Shell-Befehle auszuführen. Das wichtigste Werkzeug für Systemarbeit.</p><h3 id="tts-text-to-speech" tabindex="-1">TTS (Text-to-Speech) <a class="header-anchor" href="#tts-text-to-speech" aria-label="Permalink to &quot;TTS (Text-to-Speech)&quot;">​</a></h3><p>Sprachausgabe. Hermes kann Antworten vorlesen (Edge TTS, ElevenLabs, etc.).</p><h3 id="toolset" tabindex="-1">Toolset <a class="header-anchor" href="#toolset" aria-label="Permalink to &quot;Toolset&quot;">​</a></h3><p>Eine Gruppe verwandter Tools (z.B. <code>web</code>, <code>terminal</code>, <code>file</code>). Ein/Aus-schaltbar.</p><hr><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><h3 id="vitepress" tabindex="-1">VitePress <a class="header-anchor" href="#vitepress" aria-label="Permalink to &quot;VitePress&quot;">​</a></h3><p>Static-Site-Generator für Markdown-Dokumentationen. Basis für dieses Compendium und das WWM-Compendium.</p><h3 id="vision" tabindex="-1">Vision <a class="header-anchor" href="#vision" aria-label="Permalink to &quot;Vision&quot;">​</a></h3><p>Die Fähigkeit eines LLMs, Bilder zu analysieren. Nicht alle Modelle unterstützen Vision.</p><hr><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><h3 id="workflow-github-actions" tabindex="-1">Workflow (GitHub Actions) <a class="header-anchor" href="#workflow-github-actions" aria-label="Permalink to &quot;Workflow (GitHub Actions)&quot;">​</a></h3><p>Automatisierte Pipeline in GitHub. Z.B. &quot;bei Push → build VitePress → deploy zu Pages&quot;.</p><h3 id="worktree" tabindex="-1">Worktree <a class="header-anchor" href="#worktree" aria-label="Permalink to &quot;Worktree&quot;">​</a></h3><p>Isolierter Arbeitsbereich in Git. Ermöglicht parallele Hermes-Instanzen ohne Konflikte.</p><hr><h2 id="x" tabindex="-1">X <a class="header-anchor" href="#x" aria-label="Permalink to &quot;X&quot;">​</a></h2><h3 id="xai" tabindex="-1">xAI <a class="header-anchor" href="#xai" aria-label="Permalink to &quot;xAI&quot;">​</a></h3><p>KI-Unternehmen von Elon Musk. Betreibt das Grok-Modell, unterstützt in Hermes.</p><hr><h2 id="y" tabindex="-1">Y <a class="header-anchor" href="#y" aria-label="Permalink to &quot;Y&quot;">​</a></h2><h3 id="yaml" tabindex="-1">YAML <a class="header-anchor" href="#yaml" aria-label="Permalink to &quot;YAML&quot;">​</a></h3><p>Datenformat für Konfigurationen. Hermes&#39; <code>config.yaml</code> und SKILL.md Frontmatter nutzen YAML.</p><h3 id="yolo-modus" tabindex="-1">YOLO-Modus <a class="header-anchor" href="#yolo-modus" aria-label="Permalink to &quot;YOLO-Modus&quot;">​</a></h3><p>&quot;Du fragst nicht, ich mach einfach&quot;. Überspringt Sicherheitsabfragen bei riskanten Befehlen.</p><hr><h2 id="z" tabindex="-1">Z <a class="header-anchor" href="#z" aria-label="Permalink to &quot;Z&quot;">​</a></h2><h3 id="z-ai-glm" tabindex="-1">Z.AI / GLM <a class="header-anchor" href="#z-ai-glm" aria-label="Permalink to &quot;Z.AI / GLM&quot;">​</a></h3><p>Chinesischer KI-Provider. Unterstützt in Hermes via <code>GLM_API_KEY</code>.</p>',178)])])}const b=a(i,[["render",o]]);export{m as __pageData,b as default};
